parameters.jsCode:
const data = $input.item.json;
let response = "";
try {
  const messages = Array.isArray(data) ? data : [data];
  for (const msg of messages) {
    if (msg.content && Array.isArray(msg.content)) {
      const block = msg.content.find(c => c.text && c.text.trim() !== "");
      if (block) { response = block.text; break; }
    }
  }
  if (!response) response = JSON.stringify(data);
} catch (e) { response = JSON.stringify(data); }
let parsed;
try {
  let cleanResponse = response;
  const jsonMatch = cleanResponse.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) cleanResponse = jsonMatch[1].trim();
  parsed = JSON.parse(cleanResponse);
} catch (e) {
  parsed = { clasificacion: "Dudosa", confianza: 50, texto_ocr: "", motivo_decision: "Error parsing AI response: " + e.message, palabras_clave: [] };
}
return { json: { ai_classification: parsed.clasificacion || "Dudosa", confidence_score: typeof parsed.confianza === "number" ? parsed.confianza : 50, ocr_text: parsed.texto_ocr || "", ai_reasoning: parsed.motivo_decision || "", palabras_clave: Array.isArray(parsed.palabras_clave) ? parsed.palabras_clave : [], full_response: response } };

const input = $input.item.json;
let response = "";
if (input.output && Array.isArray(input.output) && input.output.length > 0) {
  const firstOutput = input.output[0];
  if (firstOutput.content && Array.isArray(firstOutput.content) && firstOutput.content.length > 0) {
    response = firstOutput.content[0].text || "";
  } else if (firstOutput.text) { response = firstOutput.text; }
} else if (input.message?.content) { response = input.message.content;
} else if (input.message) { response = input.message;
} else if (input.text) { response = input.text;
} else if (input.response) { response = input.response;
} else { response = JSON.stringify(input); }
let parsed;
try {
  let cleanResponse = response;
  if (typeof response === "string") {
    const jsonMatch = response.match(/```(?:json)?\s*([\s\S]*?)```/);
    if (jsonMatch) { cleanResponse = jsonMatch[1].trim(); }
  }
  parsed = typeof cleanResponse === "string" ? JSON.parse(cleanResponse) : cleanResponse;
} catch (e) {
  parsed = { clasificacion: "Dudosa", confianza: 50, texto_ocr: "", motivo_decision: "Error parsing AI response: " + e.message, palabras_clave: [] };
}
return { json: { ai_classification: parsed.clasificacion || "Dudosa", confidence_score: parsed.confianza || 50, ocr_text: parsed.texto_ocr || "", ai_reasoning: parsed.motivo_decision || "", palabras_clave: Array.isArray(parsed.palabras_clave) ? parsed.palabras_clave : [], full_response: response } };

